                    // Comma separates fields, but only if not inside quotes
                    fields.push(field.trim());  // Add the field and trim whitespace
                    field = '';
                } else {
                    // Add the character to the current field
                    field += char;
                }
            }

            fields.push(field.trim());  // Add the last field
