            table += '</tr>';

            // Add data rows
            for (var i = 1; i < rows.length; i++) {  // Start from 1 to skip headers
                table += '<tr>';
                for (var j = 0; j < rows[i].length; j++) {
                    table += '<td>' + escapeHTML(rows[i][j]) + '</td>';
                }
                table += '</tr>';
            }

            table += '</table>';
            return table;
        }

