            let pivot = arr[high];
            let i = low - 1;
            for (let j = low; j < high; j++) {
                stepsElement.textContent = `Steps: ${parseInt(stepsElement.textContent.split(': ')[1]) + 1}`;
                if (arr[j] < pivot) {
                    i++;
                    [arr[i], arr[j]] = [arr[j], arr[i]]; // Swap
                    stepsElement.textContent = `Steps: ${parseInt(stepsElement.textContent.split(': ')[1]) + 1}`;
                    renderBarChart(containerId, arr);
                    await sleep(500);
                }
            }
            [arr[i + 1], arr[high]] = [arr[high], arr[i + 1]];
            stepsElement.textContent = `Steps: ${parseInt(stepsElement.textContent.split(': ')[1]) + 1}`;
            renderBarChart(containerId, arr);
            await sleep(500);
