            const mid = Math.floor((left + right) / 2);
            await _mergeSort(arr, left, mid, temp, containerId, stepsElement);
            await _mergeSort(arr, mid + 1, right, temp, containerId, stepsElement);
            await merge(arr, left, mid, right, temp, containerId, stepsElement);
