                    outputHtml += `<p>Normal search for "${input}".</p>`;
                }
            } else {  // Safe mode
                // Simulate safe parameterized filtering
                outputHtml += `<p><strong>Safe Mode:</strong> Using parameterized filter: Searching for products where name contains "${input}" as data only.</p>`;
                results = products.filter(product => product.name.toLowerCase().includes(input.toLowerCase()));
            }

            // Display the results
            if (results.length > 0) {
                outputHtml += '<ul>';
                results.forEach(product => {
                    outputHtml += `<li>${product.name} - $${product.price}</li>`;
                });
                outputHtml += '</ul>';
            } else {
                outputHtml += '<p>No products found.</p>';
            }

            resultsDiv.innerHTML = outputHtml;  // Update the results div
        });
    </script>
