            ctx.clearRect(0, 0, canvas.width, canvas.height);  // Clear the canvas
            const startX = canvas.width / 2;  // Start at the middle
            const startY = canvas.height;     // Bottom of the canvas
            const length = 100;               // Initial branch length
            const angle = Math.PI / 2;        // Initial angle (upward)
            ctx.beginPath();
            ctx.moveTo(startX, startY);
            drawBranch(ctx, startX, startY, length, angle, depth, 0);  // Start recursion
            ctx.stroke();
        }

        function drawBranch(ctx, startX, startY, length, angle, maxDepth, currentDepth) {
            if (currentDepth > maxDepth) return;  // Base case: stop at max depth

            const endX = startX + length * Math.cos(angle);  // Calculate end point
            const endY = startY - length * Math.sin(angle);  // (Y increases downward in canvas)

            ctx.lineTo(endX, endY);  // Draw the line
            ctx.strokeStyle = 'brown';  // Branch color
            ctx.lineWidth = 2;         // Branch thickness

            if (currentDepth < maxDepth) {
                // Recursive calls for sub-branches
                const newLength = length * 0.7;  // Shrink branches
                drawBranch(ctx, endX, endY, newLength, angle - Math.PI / 6, maxDepth, currentDepth + 1);  // Left branch
                drawBranch(ctx, endX, endY, newLength, angle + Math.PI / 6, maxDepth, currentDepth + 1);  // Right branch
            }

            // For the next branches, we need to start new paths or handle it properly
            // In this simple implementation, we're using a single path for the whole tree
        }

        // Initial draw
        updateDepthAndDraw();
