                mutex = new Promise(resolve => {
                    const next = () => resolve();
                    setTimeout(next, 0);  // Ensure it's asynchronous
                });
                await previous;  // Wait for the previous operation
                try {
                    return await func();  // Run the function
                } finally {
                    // The next promise will resolve after this function completes
                }
            };
        }

