    <script>
        // Function to generate Fibonacci sequence
        function generateFibonacci(n) {
            const fibSeq = [1, 1];  // Standard base cases: starts with 1 and 1
            while (fibSeq.length < n) {
                const next = fibSeq[fibSeq.length - 1] + fibSeq[fibSeq.length - 2];
                fibSeq.push(next);
            }
            return fibSeq;
        }

        // Function to draw the spiral on a canvas
