                ctx.stroke();

                if (!isBuggy) {
                    // Correct version: Update center to the end point of the arc
                    const endAngle = angle + Math.PI / 2;
                    const endX = cx + radius * Math.cos(endAngle);
                    const endY = cy + radius * Math.sin(endAngle);
                    cx = endX;  // Update cx for next arc
                    cy = endY;  // Update cy for next arc
                    angle = endAngle;  // Update angle for next arc
                }
                // In buggy version, cx, cy, and angle are not updated here,
                // so all arcs start from the same initial center and angle continues to increase
            });
        }

        // Generate Fibonacci sequence (e.g., 8 elements)
        const fibSeq = generateFibonacci(8);  // [1, 1, 2, 3, 5, 8, 13, 21]

        // Draw the spirals
        drawSpiral('buggyCanvas', fibSeq, true);   // Buggy version
        drawSpiral('correctCanvas', fibSeq, false);  // Correct version
    </script>
