        // Function to generate Fibonacci numbers up to n terms
        function generateFibonacci(n) {
            const fib = [1, 1];  // Start with the first two Fibonacci numbers
            while (fib.length < n) {
                fib.push(fib[fib.length - 1] + fib[fib.length - 2]);
            }
            return fib;
        }

        // Function to draw the buggy spiral
        // Bug: All arcs are drawn from the same center, regardless of the spiral's progression.
