                const startAngle = angle;
                const endAngle = angle - (Math.PI / 2);  // Clockwise quarter-circle

                ctx.beginPath();
                ctx.arc(centerX, centerY, r, startAngle, endAngle, true);  // true for clockwise
                ctx.stroke();

                angle = endAngle;  // Update angle for next arc, but center stays the same
            }
        }

        // Function to draw the fixed spiral
        // Fix: Properly update the center for each arc based on the direction.
        function drawFixedSpiral(canvasId) {
            const canvas = document.getElementById(canvasId);
            const ctx = canvas.getContext('2d');
            const fib = generateFibonacci(8);  // Generate 8 Fibonacci numbers
            let x = 200;  // Starting X (adjusted for canvas center)
            let y = 200;  // Starting Y
            let angle = 0;  // Starting angle
            let directionIndex = 0;  // 0: right, 1: down, 2: left, 3: up

            ctx.strokeStyle = 'green';  // Green for fixed
            ctx.lineWidth = 2;

            for (let i = 0; i < fib.length; i++) {
                const r = fib[i];  // Radius based on Fibonacci number
                const startAngle = angle;
                const endAngle = angle - (Math.PI / 2);  // Clockwise quarter-circle
                const centerX = x;  // Current center X
                const centerY = y;  // Current center Y

                ctx.beginPath();
                ctx.arc(centerX, centerY, r, startAngle, endAngle, true);  // Draw the arc
                ctx.stroke();

                // Update position for the next arc based on the current direction
                if (directionIndex % 4 === 0) {  // Right: Move down next
                    y += r;  // Move Y down by radius
                } else if (directionIndex % 4 === 1) {  // Down: Move left next
                    x -= r;  // Move X left by radius
                } else if (directionIndex % 4 === 2) {  // Left: Move up next
                    y -= r;  // Move Y up by radius
                } else if (directionIndex % 4 === 3) {  // Up: Move right next
                    x += r;  // Move X right by radius
                }

                angle = endAngle;  // Update angle
                directionIndex++;  // Move to next direction
            }
        }

        // Run the drawings on page load
        window.onload = function() {
            drawBuggySpiral('buggyCanvas');  // Draw buggy version
