            });

            document.getElementById('leaking-widgets-container').appendChild(widget);

            // Store a reference in the array (this will cause a leak if not removed)
            leakingWidgetsArray.push(widget);  // Reference is never cleaned in this version
        }

        function deleteLeakingWidget() {
            if (leakingCounter > 0) {
                leakingCounter--;
                document.getElementById('leaking-counter').textContent = leakingCounter;

                const container = document.getElementById('leaking-widgets-container');
                const lastWidget = container.lastChild;  // Get the last widget
                if (lastWidget) {
                    container.removeChild(lastWidget);  // Remove from DOM, but no cleanup of listener or array reference
                    // Intentional leak: Event listener and array reference remain
                }
            }
        }

        // Fixed Version Variables
        let fixedCounter = 0;
        let fixedWidgetsArray = [];  // This array will be properly cleaned

        function addFixedWidget() {
            fixedCounter++;
            document.getElementById('fixed-counter').textContent = fixedCounter;

            const widget = document.createElement('div');
            widget.className = 'widget';
            widget.textContent = `Fixed Widget ${fixedCounter}`;

            // Add an event listener (e.g., a click handler)
            const handler = function() {
                alert(`Clicked on Fixed Widget ${fixedCounter}`);
            };
            widget.addEventListener('click', handler);

            document.getElementById('fixed-widgets-container').appendChild(widget);

            // Store a reference in the array
            fixedWidgetsArray.push({ element: widget, listener: handler });  // Store both for easy cleanup
        }

        function deleteFixedWidget() {
            if (fixedCounter > 0) {
                fixedCounter--;
                document.getElementById('fixed-counter').textContent = fixedCounter;

                const container = document.getElementById('fixed-widgets-container');
                const lastWidgetData = fixedWidgetsArray.pop();  // Get and remove the last reference from the array
                const lastWidget = lastWidgetData.element;

                if (lastWidget) {
                    // Proper cleanup: Remove the event listener
                    const handler = lastWidgetData.listener;
                    lastWidget.removeEventListener('click', handler);

                    container.removeChild(lastWidget);  // Remove from DOM
                    // Now, with no references, the GC can collect it
                }
            }
        }
