Below is a complete, self-contained HTML file that visualizes a singly linked list. It includes:

- **Visualization**: Each node is rendered as a box (using div elements) showing its value. Nodes are connected by arrows (using Unicode characters for simplicity).
- **Controls**:
  - **Insert at Head**: Adds a new node at the beginning of the list.
  - **Insert at Tail**: Adds a new node at the end of the list.
  - **Delete by Value**: Removes the first occurrence of a node with the specified value.
  - **Search**: Highlights the first node with the specified value by changing its background color.
- **Empty List Handling**: If the list is empty, it displays a message like "The list is empty." in the visualization area.
- **User Interaction**: Includes an input field for entering values and buttons for each operation. Results or errors (e.g., "Value not found") are displayed as alerts or updated in the UI.

This file uses only vanilla HTML, CSS, and JavaScript, making it fully self-contained. You can save it as an `.html` file (e.g., `linked_list_visualizer.html`) and open it in a web browser to interact with it.

```html
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Singly Linked List Visualizer</title>
    <style>
        /* Basic styling for the page */
        body {
            font-family: Arial, sans-serif;
            margin: 20px;
        }

        #controls {
            margin-bottom: 20px;
        }

        #listContainer {
            display: flex;
            align-items: center;
            flex-wrap: wrap;
            gap: 10px;
        }

        .node {
            padding: 10px;
            background-color: #f0f0f0;
            border: 1px solid #ccc;
            border-radius: 5px;
            position: relative;
            min-width: 50px;
            text-align: center;
            transition: background-color 0.3s;
        }

        .node.highlighted {
            background-color: #ff0; /* Yellow highlight for searched node */
        }

        .arrow {
            font-size: 24px;
            color: #333;
            margin: 0 5px;
        }

        /* Empty list message */
        .empty-message {
            color: #888;
            font-style: italic;
        }
    </style>
</head>
<body>
    <h1>Singly Linked List Visualizer</h1>

    <div id="controls">
        <input type="text" id="valueInput" placeholder="Enter a value (e.g., 5)">
        <button id="insertHead">Insert at Head</button>
        <button id="insertTail">Insert at Tail</button>
        <button id="deleteValue">Delete by Value</button>
        <button id="searchValue">Search Value</button>
    </div>

    <div id="listContainer">
        <!-- Linked list will be rendered here -->
    </div>

    <script>
        // Node class for the linked list
        class Node {
            constructor(value) {
                this.value = value;
                this.next = null;
            }
        }

        // LinkedList class
        class LinkedList {
            constructor() {
                this.head = null;
            }

            // Insert at head
            insertAtHead(value) {
                const newNode = new Node(value);
                newNode.next = this.head;
                this.head = newNode;
            }

            // Insert at tail
            insertAtTail(value) {
                const newNode = new Node(value);
                if (!this.head) {
                    this.head = newNode;
                    return;
                }
                let current = this.head;
                while (current.next) {
                    current = current.next;
                }
                current.next = newNode;
            }

            // Delete by value (first occurrence)
            deleteByValue(value) {
                if (!this.head) return false; // Empty list

                if (this.head.value === value) {
                    this.head = this.head.next;
                    return true;
                }

                let current = this.head;
                while (current.next) {
                    if (current.next.value === value) {
                        current.next = current.next.next;
                        return true;
                    }
                    current = current.next;
                }
                return false; // Value not found
            }

            // Search for value and return the node (for highlighting)
            search(value) {
                let current = this.head;
                while (current) {
                    if (current.value === value) {
                        return current; // Return the node if found
                    }
                    current = current.next;
                }
                return null; // Not found
            }

            // Helper to convert list to array for rendering
            toArray() {
                const array = [];
                let current = this.head;
                while (current) {
                    array.push(current.value);
                    current = current.next;
                }
                return array;
            }
        }

        // Initialize the linked list
        const linkedList = new LinkedList();
        const listContainer = document.getElementById('listContainer');
        const valueInput = document.getElementById('valueInput');

        // Function to render the linked list
        function renderLinkedList(highlightValue = null) {
            listContainer.innerHTML = ''; // Clear existing content
            const values = linkedList.toArray();

            if (values.length === 0) {
                // Handle empty list
                const emptyMessage = document.createElement('div');
                emptyMessage.className = 'empty-message';
                emptyMessage.textContent = 'The list is empty.';
                listContainer.appendChild(emptyMessage);
                return;
            }

            values.forEach((value, index) => {
                const nodeDiv = document.createElement('div');
                nodeDiv.className = 'node';
                if (value === highlightValue) {
                    nodeDiv.classList.add('highlighted'); // Add highlight class
                }
                nodeDiv.textContent = value;

                listContainer.appendChild(nodeDiv);

                if (index < values.length - 1) {
                    // Add arrow between nodes
                    const arrowDiv = document.createElement('div');
                    arrowDiv.className = 'arrow';
                    arrowDiv.textContent = '→'; // Unicode arrow
                    listContainer.appendChild(arrowDiv);
                }
            });
        }

        // Event listeners for buttons
        document.getElementById('insertHead').addEventListener('click', () => {
            const value = valueInput.value.trim();
            if (value) {
                linkedList.insertAtHead(value);
                renderLinkedList(); // Re-render without highlight
                valueInput.value = ''; // Clear input
            } else {
                alert('Please enter a value.');
            }
        });

        document.getElementById('insertTail').addEventListener('click', () => {
            const value = valueInput.value.trim();
            if (value) {
                linkedList.insertAtTail(value);
                renderLinkedList();
                valueInput.value = '';
            } else {
                alert('Please enter a value.');
            }
        });

        document.getElementById('deleteValue').addEventListener('click', () => {
            const value = valueInput.value.trim();
            if (value) {
                const success = linkedList.deleteByValue(value);
                if (success) {
                    renderLinkedList();
                } else {
                    alert('Value not found in the list.');
                }
                valueInput.value = '';
            } else {
                alert('Please enter a value.');
            }
        });

        document.getElementById('searchValue').addEventListener('click', () => {
            const value = valueInput.value.trim();
            if (value) {
                const foundNode = linkedList.search(value);
                if (foundNode) {
                    renderLinkedList(foundNode.value); // Re-render with highlight
                    setTimeout(() => renderLinkedList(), 1000); // Remove highlight after 1 second
                } else {
                    alert('Value not found in the list.');
                    renderLinkedList(); // Re-render without highlight
                }
                valueInput.value = '';
            } else {
                alert('Please enter a value.');
            }
        });

        // Initial render
        renderLinkedList();
    </script>
</body>
</html>
