    <h1>CSV to HTML Table Parser</h1>
    <p>Paste your CSV data into the textarea below and click the button to parse it into a table.</p>

    <textarea id="csvInput" placeholder='Example:
"Name","Age","City"
"John, Doe",30,"New York"
"Jane ""The Great"" Smith",25,"San Francisco"
Another,Row,With,Fewer,Columns'></textarea>

    <button onclick="parseCSV()">Parse CSV</button>

    <div id="output"></div> <!-- This is where the table will be displayed -->

    <script>
        // Function to escape HTML to prevent XSS
        function escapeHTML(str) {
            if (typeof str !== 'string') return '';
            return str
                .replace(/&/g, '&amp;')
                .replace(/</g, '&lt;')
                .replace(/>/g, '&gt;')
                .replace(/"/g, '&quot;')
                .replace(/'/g, '&#39;');
        }

        // Function to parse CSV string into a 2D array
        function parseCSVString(csvString) {
            const lines = csvString.trim().split('\n'); // Split into lines
            const result = [];

            for (const line of lines) {
                const fields = [];
                let field = '';
                let inQuotes = false;

                for (let i = 0; i < line.length; i++) {
                    const char = line[i];

                    if (char === '"') {
                        // Handle quoted fields and escaped quotes
                        if (inQuotes && i + 1 < line.length && line[i + 1] === '"') {
                            // Escaped quote (e.g., "")
                            field += '"'; // Add a single quote
                            i++; // Skip the next quote
                        } else {
                            inQuotes = !inQuotes; // Toggle quoted state
                        }
                    } else if (char === ',' && !inQuotes) {
                        // End of field if not inside quotes
                        fields.push(field.trim()); // Add the field and trim whitespace
                        field = '';
                    } else {
                        field += char; // Add character to the current field
                    }
                }

                fields.push(field.trim()); // Add the last field
                result.push(fields); // Add the row to the result
            }

            return result; // Return the 2D array
        }

        // Main function to parse CSV and generate the table
        function parseCSV() {
            const csvInput = document.getElementById('csvInput').value; // Get the textarea value
            const data = parseCSVString(csvInput); // Parse the CSV string

            if (data.length === 0) {
                document.getElementById('output').innerHTML = '<p>No data to display.</p>';
                return;
            }

            let tableHTML = '<table>';

            for (let i = 0; i < data.length; i++) {
                tableHTML += `<tr class="${i % 2 === 0 ? 'even' : 'odd'}">`; // Alternating classes
                for (const cell of data[i]) {
                    tableHTML += `<td>${escapeHTML(cell)}</td>`; // Escape and add each cell
                }
                tableHTML += '</tr>';
            }

            tableHTML += '</table>';

            document.getElementById('output').innerHTML = tableHTML; // Insert the table into the output div
        }
    </script>
</body>
</html>
