    <h1>CSV to Table Converter</h1>
    <p>Paste your CSV data into the textarea below and click "Parse". It handles quoted fields, escaped quotes, and varying column counts.</p>

    <textarea id="csvInput" placeholder='Example:
"Name","Age","City"
"John Doe", 30, "New York, NY"  // Commas in quotes are handled
"Jane \"Smith\"",25,""          // Escaped quotes and empty fields
Alice,28                         // Varying columns'></textarea>

    <button id="parseButton">Parse</button>

    <div id="output"></div>  <!-- This is where the table will appear -->

    <script>
        // Function to escape HTML to prevent XSS
        function escapeHTML(str) {
            if (typeof str !== 'string') return '';
            return str
                .replace(/&/g, '&amp;')
                .replace(/</g, '&lt;')
                .replace(/>/g, '&gt;')
                .replace(/"/g, '&quot;')
                .replace(/'/g, '&#039;');
        }

        // CSV Parser function
        function parseCSV(csvString) {
            const lines = csvString.trim().split('\n').filter(line => line.trim() !== ''); // Split into lines and skip empty ones
            const result = [];

            for (const line of lines) {
                const fields = [];
                let field = '';
                let inQuotes = false;

                for (let i = 0; i < line.length; i++) {
                    const char = line[i];

                    if (char === '"') {
                        // Handle quotes: Toggle inQuotes, but check for escaped quotes
                        if (inQuotes && line[i + 1] === '"') {
                            field += '"';  // Escaped quote: Add a single "
                            i++;  // Skip the next quote
                        } else {
                            inQuotes = !inQuotes;  // Enter or exit quoted mode
                        }
                    } else if (char === ',' && !inQuotes) {
                        // Comma outside quotes: End of field
                        fields.push(field.trim());  // Trim and add the field
                        field = '';
                    } else {
                        // Add the character to the current field
                        field += char;
                    }
                }

                // Add the last field
                if (field.trim() !== '') {
                    fields.push(field.trim());
                }

                result.push(fields);  // Add the row, even if it has varying lengths
            }

            return result;
        }

        // Function to generate the HTML table
        function generateTable(data) {
            if (data.length === 0) return '<p>No data to display.</p>';

            let tableHTML = '<table>';

            for (let i = 0; i < data.length; i++) {
                tableHTML += '<tr>';
                for (let j = 0; j < data[i].length; j++) {
                    const cellContent = escapeHTML(data[i][j]);  // Escape for safety
                    if (i === 0) {
                        // First row as headers
                        tableHTML += `<th>${cellContent}</th>`;
                    } else {
                        tableHTML += `<td>${cellContent}</td>`;
                    }
                }
                tableHTML += '</tr>';
            }

            tableHTML += '</table>';
            return tableHTML;
        }

        // Event listener for the button
        document.getElementById('parseButton').addEventListener('click', () => {
            const csvInput = document.getElementById('csvInput').value;
            const outputDiv = document.getElementById('output');

            try {
                const parsedData = parseCSV(csvInput);
                outputDiv.innerHTML = generateTable(parsedData);  // Generate and insert the table
            } catch (error) {
                outputDiv.innerHTML = `<p class="error">Error parsing CSV: ${error.message}</p>`;
            }
        });
    </script>
</body>
</html>
