    <h1>Linked List Visualization</h1>
    <div id="controls">
        <input type="number" id="valueInput" placeholder="Enter a value">
        <button id="insertHead">Insert at Head</button>
        <button id="insertTail">Insert at Tail</button>
        <button id="deleteValue">Delete by Value</button>
        <button id="searchValue">Search</button>
    </div>
    <div id="listContainer">
        <p class="empty-message">The list is empty.</p>
    </div>

    <script>
        // Node class for the linked list
        class Node {
            constructor(data) {
                this.data = data;
                this.next = null;
            }
        }

        // LinkedList class
        class LinkedList {
            constructor() {
                this.head = null;
            }

            insertAtHead(data) {
                const newNode = new Node(data);
                newNode.next = this.head;
                this.head = newNode;
            }

            insertAtTail(data) {
                const newNode = new Node(data);
                if (!this.head) {
                    this.head = newNode;
                    return;
                }
                let current = this.head;
                while (current.next) {
                    current = current.next;
                }
                current.next = newNode;
            }

            deleteByValue(value) {
                if (!this.head) {
                    alert("The list is empty!");
                    return;
                }
                if (this.head.data === value) {
                    this.head = this.head.next;
                    return;
                }
                let current = this.head;
                while (current.next) {
                    if (current.next.data === value) {
                        current.next = current.next.next;
                        return;
                    }
                    current = current.next;
                }
                alert("Value not found in the list!");
            }

            // No need for a separate search method; we'll handle it in rendering
        }

        const linkedList = new LinkedList();
        const listContainer = document.getElementById('listContainer');
        const valueInput = document.getElementById('valueInput');

        function render(highlightValue = null) {
            listContainer.innerHTML = '';  // Clear the container
            if (!linkedList.head) {
                listContainer.innerHTML = '<p class="empty-message">The list is empty.</p>';
                return;
            }

            let current = linkedList.head;
            while (current) {
                const nodeDiv = document.createElement('div');
                nodeDiv.className = 'node';
                nodeDiv.textContent = current.data;

                // Add highlight if the current node's data matches the highlight value
                if (highlightValue !== null && current.data === highlightValue) {
                    nodeDiv.classList.add('highlighted');
                }

                listContainer.appendChild(nodeDiv);

                if (current.next) {
                    const arrowDiv = document.createElement('div');
                    arrowDiv.className = 'arrow';
                    arrowDiv.textContent = '→';  // Unicode arrow
                    listContainer.appendChild(arrowDiv);
                }

                current = current.next;
            }
        }

        // Event listeners for controls
        document.getElementById('insertHead').addEventListener('click', () => {
            const value = parseInt(valueInput.value);
            if (!isNaN(value)) {
                linkedList.insertAtHead(value);
                render();  // Re-render without highlight
                valueInput.value = '';  // Clear input
            } else {
                alert('Please enter a valid number.');
            }
        });

        document.getElementById('insertTail').addEventListener('click', () => {
            const value = parseInt(valueInput.value);
            if (!isNaN(value)) {
                linkedList.insertAtTail(value);
                render();  // Re-render without highlight
                valueInput.value = '';  // Clear input
            } else {
                alert('Please enter a valid number.');
            }
        });

        document.getElementById('deleteValue').addEventListener('click', () => {
            const value = parseInt(valueInput.value);
            if (!isNaN(value)) {
                linkedList.deleteByValue(value);
                render();  // Re-render without highlight
                valueInput.value = '';  // Clear input
            } else {
                alert('Please enter a valid number.');
            }
        });

        document.getElementById('searchValue').addEventListener('click', () => {
            const value = parseInt(valueInput.value);
            if (!isNaN(value)) {
                render(value);  // Re-render with highlight for the value
                valueInput.value = '';  // Clear input
            } else {
                alert('Please enter a valid number.');
            }
        });
    </script>
</body>
