    <script>
        // Generate a random array of 10 numbers (1-100)
        function generateRandomArray() {
            return Array.from({length: 10}, () => Math.floor(Math.random() * 100) + 1);
        }

        let originalArray = generateRandomArray(); // Shared array for all

        // Function to render the bar chart
        function renderBars(containerId, array) {
            const container = document.getElementById(containerId);
            container.innerHTML = ''; // Clear previous bars
            const barWidth = 100 / array.length + '%'; // Even spacing
            array.forEach((value, index) => {
                const bar = document.createElement('div');
                bar.className = 'bar';
                bar.style.width = barWidth;
                bar.style.left = (index * (100 / array.length)) + '%';
                bar.style.height = (value / 100 * 100) + '%'; // Scale height (assuming max 100)
                bar.style.backgroundColor = '#007bff';
                container.appendChild(bar);
            });
        }

        // Bubble Sort with step-by-step animation
        async function bubbleSort(array) {
            let steps = 0;
            let n = array.length;
            for (let i = 0; i < n; i++) {
                for (let j = 0; j < n - i - 1; j++) {
                    steps++; // Increment for each comparison
                    document.getElementById('bubbleSteps').textContent = steps;
                    if (array[j] > array[j + 1]) {
                        [array[j], array[j + 1]] = [array[j + 1], array[j]]; // Swap
                        renderBars('bubbleChart', array); // Re-render after swap
                        await sleep(500); // Pause for animation
                    }
                }
            }
            return array;
        }

        // Quick Sort with step-by-step animation
        async function quickSort(array, start = 0, end = array.length - 1) {
            if (start < end) {
                let steps = parseInt(document.getElementById('quickSteps').textContent) || 0;
                let pivotIndex = await partition(array, start, end, steps);
                steps += (end - start); // Approximate steps for partitioning
                document.getElementById('quickSteps').textContent = steps;
                await quickSort(array, start, pivotIndex - 1);
                await quickSort(array, pivotIndex + 1, end);
            }
            renderBars('quickChart', array); // Re-render after recursion
            return array;
        }

        async function partition(array, start, end, steps) {
            let pivot = array[end];
            let i = start - 1;
            for (let j = start; j < end; j++) {
                steps++; // Increment for each comparison
                document.getElementById('quickSteps').textContent = steps;
                if (array[j] < pivot) {
                    i++;
                    [array[i], array[j]] = [array[j], array[i]]; // Swap
                    renderBars('quickChart', array);
                    await sleep(500); // Pause
                }
            }
            [array[i + 1], array[end]] = [array[end], array[i + 1]];
            return i + 1;
        }

        // Merge Sort with step-by-step animation
        async function mergeSort(array) {
            let steps = 0;
            if (array.length > 1) {
                const mid = Math.floor(array.length / 2);
                let left = array.slice(0, mid);
                let right = array.slice(mid);

                left = await mergeSort(left);
                right = await mergeSort(right);

                array = merge(left, right, steps);
            }
            renderBars('mergeChart', array); // Re-render after merge
            return array;
        }

        function merge(left, right, steps) {
            let array = [];
            let i = 0, j = 0;
            while (i < left.length && j < right.length) {
                steps++; // Increment for each comparison
                document.getElementById('mergeSteps').textContent = steps;
                if (left[i] < right[j]) {
                    array.push(left[i]);
                    i++;
                } else {
                    array.push(right[j]);
                    j++;
                }
            }
            while (i < left.length) {
                array.push(left[i]);
                i++;
            }
            while (j < right.length) {
                array.push(right[j]);
                j++;
            }
            return array; // Note: Merge Sort is not in-place, so we return a new array
        }

        // Helper function for delays
        function sleep(ms) {
            return new Promise(resolve => setTimeout(resolve, ms));
        }

        // Start button event
        document.getElementById('startButton').addEventListener('click', async () => {
            originalArray = generateRandomArray(); // New random array each time
            let bubbleArray = [...originalArray]; // Copy for Bubble Sort
            let quickArray = [...originalArray];  // Copy for Quick Sort
            let mergeArray = [...originalArray];  // Copy for Merge Sort

            renderBars('bubbleChart', bubbleArray);
            renderBars('quickChart', quickArray);
            renderBars('mergeChart', mergeArray);

            document.getElementById('bubbleSteps').textContent = '0';
            document.getElementById('quickSteps').textContent = '0';
            document.getElementById('mergeSteps').textContent = '0';

            await Promise.all([
                bubbleSort(bubbleArray),
                quickSort(quickArray),
                mergeSort(mergeArray) // Merge Sort returns a new array, so handle accordingly
            ]);

            // After sorting, update the final state
            renderBars('mergeChart', mergeArray); // Ensure final render
        });
    </script>
</body>
