        // Bubble Sort generator (yields after each swap for animation)
        function* bubbleSort(arr) {
            let steps = 0;  // Counter for comparisons and swaps
            let n = arr.length;
            for (let i = 0; i < n; i++) {
                for (let j = 0; j < n - i - 1; j++) {
