                    if (arr[j] > arr[j + 1]) {
                        [arr[j], arr[j + 1]] = [arr[j + 1], arr[j]];  // Swap
                        steps++;  // Increment for swap
                        yield { array: [...arr], steps };  // Yield a copy of the array and steps
                    }
