                for (let j = low; j < high; j++) {
                    steps++;  // Increment for comparison
                    if (arr[j] < pivot) {
                        i++;
                        [arr[i], arr[j]] = [arr[j], arr[i]];  // Swap
                        steps++;  // Increment for swap
                        yield { array: [...arr], steps };  // Yield after swap
                    }
                }
                [arr[i + 1], arr[high]] = [arr[high], arr[i + 1]];
                steps++;  // Increment for final swap
                yield { array: [...arr], steps };  // Yield after partition
                return i + 1;
            }

            if (low < high) {
                let pi = yield* partition(arr, low, high);
                yield* quickSort(arr, low, pi - 1);
                yield* quickSort(arr, pi + 1, high);
            }
            return { array: arr, steps };  // Final state (though steps are accumulated per call)
        }

        // Mergesort generator (yields after each merge step)
        function* mergeSort(arr) {
            let steps = 0;  // Counter for comparisons and merges
            function* merge(arr, l, m, r) {
                let n1 = m - l + 1;
                let n2 = r - m;
                let L = arr.slice(l, m + 1);
