            let steps = 0;
            async function partition(low, high) {
                let pivot = arr[high];
                let i = low - 1;
                for (let j = low; j < high; j++) {
                    steps++; // Increment for each comparison
                    stepsElement.textContent = steps + parseInt(stepsElement.textContent); // Cumulative for demo

                    if (arr[j] < pivot) {
                        i++;
                        [arr[i], arr[j]] = [arr[j], arr[i]]; // Swap
                        bars[i].style.backgroundColor = '#ff0000';
                        bars[j].style.backgroundColor = '#ff0000';
                        await sleep(300); // Faster animation
                        bars[i].style.height = `${arr[i] * (150 / Math.max(...originalArray))}px`;
                        bars[j].style.height = `${arr[j] * (150 / Math.max(...originalArray))}px`;
                        bars[i].style.backgroundColor = '#007bff';
                        bars[j].style.backgroundColor = '#007bff';
                    }
                }
                [arr[i + 1], arr[high]] = [arr[high], arr[i + 1]];
                bars[i + 1].style.backgroundColor = '#ff0000';
                bars[high].style.backgroundColor = '#ff0000';
                await sleep(300);
                bars[i + 1].style.height = `${arr[i + 1] * (150 / Math.max(...originalArray))}px`;
                bars[high].style.height = `${arr[high] * (150 / Math.max(...originalArray))}px`;
                bars[i + 1].style.backgroundColor = '#007bff';
                bars[high].style.backgroundColor = '#007bff';
                return i + 1;
            }

            async function sort(low, high) {
                if (low < high) {
                    let pi = await partition(low, high);
                    await sort(low, pi - 1);
                    await sort(pi + 1, high);
                }
            }

            let arr = array.slice(); // Copy array
            const barsContainer = document.querySelectorAll('#quickBars .bar');
            await sort(0, arr.length - 1);
            barsContainer.forEach(bar => bar.classList.add('sorted'));
            return arr;
        }

        // Merge Sort implementation with steps and animation
