                }
                ctx.fillRect(x, y, barWidth - 2, barHeight); // -2 for spacing
                ctx.fillStyle = '#2c3e50'; // Dark text
                ctx.fillText(value, x + barWidth / 4, y + 20); // Label bars
            });
        }

        // Bubble Sort generator (yields after each swap for animation)
        function* bubbleSort(arr) {
            let n = arr.length;
            let steps = 0;
            for (let i = 0; i < n; i++) {
                for (let j = 0; j < n - i - 1; j++) {
                    steps++; // Count comparisons
                    if (arr[j] > arr[j + 1]) {
                        [arr[j], arr[j + 1]] = [arr[j + 1], arr[j]]; // Swap
                        steps++; // Count swaps
                        yield { array: [...arr], highlights: [j, j+1] }; // Yield for animation
                    } else {
