            let steps = 0; // Track steps
            if (low < high) {
                const pivotIndex = await partition(arr, low, high, steps);
                steps += pivotIndex.steps; // Add steps from partition
                await quickSort(arr, low, pivotIndex.index - 1); // Left subarray
                await quickSort(arr, pivotIndex.index + 1, high); // Right subarray
            }
            return steps;
        }

        async function partition(arr, low, high, steps) {
            const pivot = arr[high];
            let i = low - 1;
            for (let j = low; j < high; j++) {
                steps++; // Comparison
                if (arr[j] < pivot) {
                    i++;
                    [arr[i], arr[j]] = [arr[j], arr[i]]; // Swap
                    steps++; // Swap
                    drawBars('quickCanvas', arr, [i, j]); // Animate
                    await sleep(50); // Slow down a bit for visibility
                }
            }
            [arr[i + 1], arr[high]] = [arr[high], arr[i + 1]];
            steps++; // Final swap
            drawBars('quickCanvas', arr, [i + 1, high]);
            await sleep(50);
            return { index: i + 1, steps };
        }

