        async function mergeSort(arr, l = 0, r = arr.length - 1) {
            let steps = 0;
            if (l < r) {
                const m = Math.floor((l + r) / 2);
                steps += await mergeSort(arr, l, m); // Left half
                steps += await mergeSort(arr, m + 1, r); // Right half
                steps += await merge(arr, l, m, r); // Merge
            }
            return steps;
        }

        async function merge(arr, l, m, r) {
            let steps = 0;
            let n1 = m - l + 1;
            let n2 = r - m;
            let L = arr.slice(l, m + 1);
