            margin-top: 20px;
            cursor: pointer;
        }
    </style>
</head>
<body>
    <h1>Sorting Algorithm Comparison</h1>
    <p>This visualization compares Bubble Sort with two faster algorithms: Quick Sort and Merge Sort. Click the button to start sorting the same randomized array side by side.</p>
    <button id="startButton">Start Sorting</button>

    <div class="container">
        <div class="algorithm-section" id="bubbleSortSection">
            <h2>Bubble Sort</h2>
            <canvas id="bubbleSortCanvas"></canvas>
            <div class="step-counter" id="bubbleSortSteps">Steps: 0</div>
            <div class="explanation">
                Bubble Sort repeatedly swaps adjacent elements if they are in the wrong order. <strong>Time Complexity: O(n²)</strong> in the worst and average cases, making it inefficient for large datasets.
            </div>
        </div>

        <div class="algorithm-section" id="quickSortSection">
            <h2>Quick Sort</h2>
            <canvas id="quickSortCanvas"></canvas>
            <div class="step-counter" id="quickSortSteps">Steps: 0</div>
            <div class="explanation">
                Quick Sort uses a divide-and-conquer approach by selecting a pivot and partitioning the array. <strong>Time Complexity: Average O(n log n)</strong>, but can be O(n²) in the worst case with poor pivot selection.
            </div>
        </div>

        <div class="algorithm-section" id="mergeSortSection">
            <h2>Merge Sort</h2>
            <canvas id="mergeSortCanvas"></canvas>
            <div class="step-counter" id="mergeSortSteps">Steps: 0</div>
            <div class="explanation">
                Merge Sort divides the array into halves, sorts them, and merges them back. <strong>Time Complexity: O(n log n)</strong> in all cases, making it efficient and stable.
            </div>
        </div>
    </div>

    <script>
        // Generate a random array (e.g., 15 elements between 1 and 100)
        const arraySize = 15;
        function generateRandomArray() {
            return Array.from({length: arraySize}, () => Math.floor(Math.random() * 100) + 1);
        }

        let originalArray = generateRandomArray();  // Shared array for all algorithms

        const canvases = {
            bubble: document.getElementById('bubbleSortCanvas').getContext('2d'),
            quick: document.getElementById('quickSortCanvas').getContext('2d'),
            merge: document.getElementById('mergeSortCanvas').getContext('2d')
        };

        const stepCounters = {
            bubble: document.getElementById('bubbleSortSteps'),
            quick: document.getElementById('quickSortSteps'),
            merge: document.getElementById('mergeSortSteps')
        };

        // Utility function to draw the array on a canvas
        function drawArray(ctx, array, highlightIndices = []) {
            const canvasWidth = ctx.canvas.width;
            const canvasHeight = ctx.canvas.height;
            const barWidth = canvasWidth / array.length;
            const maxValue = Math.max(...array);

            ctx.clearRect(0, 0, canvasWidth, canvasHeight);
            array.forEach((value, index) => {
                const barHeight = (value / maxValue) * canvasHeight * 0.8;  // 80% of canvas height
                ctx.fillStyle = highlightIndices.includes(index) ? 'red' : 'blue';  // Highlight if needed
                ctx.fillRect(index * barWidth, canvasHeight - barHeight, barWidth - 1, barHeight);
            });
        }

        // Bubble Sort generator
        function* bubbleSort(arr) {
            let steps = 0;
            let n = arr.length;
            for(let i = 0; i < n; i++) {
                for(let j = 0; j < n - i - 1; j++) {
                    steps++;
                    yield { array: [...arr], indices: [j, j+1], steps };  // Yield after each comparison
                    if(arr[j] > arr[j+1]) {
                        [arr[j], arr[j+1]] = [arr[j+1], arr[j]];
                        yield { array: [...arr], indices: [j, j+1], steps };  // Yield after swap
                    }
                }
            }
            return steps;  // Final steps
        }

        // Quick Sort generator (simplified, in-place)
        function* quickSort(arr, low = 0, high = arr.length - 1) {
            let steps = 0;  // Local steps, but we'll accumulate globally
            function* partition(arr, low, high) {
                let pivot = arr[high];
                let i = low - 1;
                for(let j = low; j < high; j++) {
                    steps++;
                    yield { array: [...arr], indices: [j, high], steps };  // Yield for comparison
                    if(arr[j] < pivot) {
                        i++;
                        [arr[i], arr[j]] = [arr[j], arr[i]];
                        yield { array: [...arr], indices: [i, j], steps };  // Yield for swap
                    }
                }
                [arr[i+1], arr[high]] = [arr[high], arr[i+1]];
                yield { array: [...arr], indices: [i+1, high], steps };  // Yield for final swap
                return i+1;
            }

            if(low < high) {
                let piIndex = yield* partition(arr, low, high);
                yield* quickSort(arr, low, piIndex - 1);
                yield* quickSort(arr, piIndex + 1, high);
            }
            return steps;
        }

        // Merge Sort generator
        function* mergeSort(arr) {
            let steps = 0;
            function* merge(arr, l, m, r) {
                let n1 = m - l + 1;
                let n2 = r - m;
                let L = arr.slice(l, m+1);
                let R = arr.slice(m+1, r+1);

                let i = 0, j = 0, k = l;
                while(i < n1 && j < n2) {
                    steps++;
                    yield { array: [...arr], indices: [k, l+i, m+1+j], steps };  // Yield for merge step
                    if(L[i] <= R[j]) {
                        arr[k] = L[i];
                        i++;
                    } else {
                        arr[k] = R[j];
                        j++;
                    }
                    k++;
                    yield { array: [...arr], indices: [k-1], steps };  // Yield after assignment
                }

                while(i < n1) {
                    arr[k] = L[i];
                    i++;
                    k++;
                    steps++;
                    yield { array: [...arr], indices: [k-1], steps };
                }

                while(j < n2) {
                    arr[k] = R[j];
                    j++;
                    k++;
                    steps++;
                    yield { array: [...arr], indices: [k-1], steps };
                }
            }

            function* sort(arr, l, r) {
                if(l >= r) return;
                let m = l + Math.floor((r - l) / 2);
                yield* sort(arr, l, m);
                yield* sort(arr, m+1, r);
                yield* merge(arr, l, m, r);
            }

            yield* sort(arr, 0, arr.length - 1);
            return steps;
        }

        // Start the sorting
        document.getElementById('startButton').addEventListener('click', () => {
            originalArray = generateRandomArray();  // Reset array
            let bubbleArray = [...originalArray];
            let quickArray = [...originalArray];
            let mergeArray = [...originalArray];

            let bubbleGen = bubbleSort(bubbleArray);
            let quickGen = quickSort(quickArray);
            let mergeGen = mergeSort(mergeArray);

            let globalSteps = { bubble: 0, quick: 0, merge: 0 };

            function animate() {
                let bubbleResult = bubbleGen.next();
                let quickResult = quickGen.next();
                let mergeResult = mergeGen.next();

                if (!bubbleResult.done) {
                    drawArray(canvases.bubble, bubbleResult.value.array, bubbleResult.value.indices);
                    globalSteps.bubble = bubbleResult.value.steps;
                    stepCounters.bubble.textContent = `Steps: ${globalSteps.bubble}`;
                }

                if (!quickResult.done) {
                    drawArray(canvases.quick, quickResult.value.array, quickResult.value.indices);
                    globalSteps.quick += quickResult.value.steps || 0;  // Accumulate for Quick Sort
                    stepCounters.quick.textContent = `Steps: ${globalSteps.quick}`;
                }

                if (!mergeResult.done) {
                    drawArray(canvases.merge, mergeResult.value.array, mergeResult.value.indices);
                    globalSteps.merge += mergeResult.value.steps || 0;  // Accumulate for Merge Sort
                    stepCounters.merge.textContent = `Steps: ${globalSteps.merge}`;
                }

                if (!bubbleResult.done || !quickResult.done || !mergeResult.done) {
                    requestAnimationFrame(animate);  // Continue animation
                } else {
                    // Final draw
                    drawArray(canvases.bubble, bubbleArray);
                    drawArray(canvases.quick, quickArray);
                    drawArray(canvases.merge, mergeArray);
                    alert('Sorting complete! Check the step counters to see the differences.');
                }
            }

            // Initial draw
            drawArray(canvases.bubble, originalArray);
            drawArray(canvases.quick, originalArray);
            drawArray(canvases.merge, originalArray);

            stepCounters.bubble.textContent = 'Steps: 0';
            stepCounters.quick.textContent = 'Steps: 0';
            stepCounters.merge.textContent = 'Steps: 0';

            animate();  // Start animation loop
        });
    </script>
</body>
</html>
```

