            { id: 4, name: 'Keyboard', price: 49 },
            { id: 5, name: 'Monitor', price: 199 }
        ];

        // Function for vulnerable filtering (simulates string concatenation)
        function vulnerableFilter(searchTerm) {
            try {
                // Directly use searchTerm to create a regex, which can be injected
                const regex = new RegExp(searchTerm, 'i');  // 'i' for case-insensitive
                return products.filter(product => regex.test(product.name));
            } catch (error) {
                return [{ error: 'Invalid input caused an error (e.g., malformed regex).' }];
            }
        }

        // Function for safe filtering (parameterized-like)
        function safeFilter(searchTerm) {
            const lowerSearch = searchTerm.toLowerCase();  // Treat as literal string
            return products.filter(product => product.name.toLowerCase().includes(lowerSearch));
        }

        // Event listener for the search button
        document.getElementById('searchButton').addEventListener('click', () => {
