            // Get results for safe mode
            const safeResults = safeFilter(searchTerm);
            displayResults('safeResults', safeResults, 'safe');
        });

        // Helper function to display results
        function displayResults(elementId, results, mode) {
            const resultsDiv = document.getElementById(elementId);
            if (results.length === 0) {
                resultsDiv.innerHTML = '<p>No results found.</p>';
                return;
            }

            let html = '<ul>';
            results.forEach(item => {
