                    html += `<li>${item.error}</li>`;
                } else {
                    html += `<li>${item.name} - $${item.price}</li>`;
                }
            });
            html += '</ul>';
            resultsDiv.innerHTML = html;

            // Add a note for vulnerable mode if all items are returned
            if (mode === 'vulnerable' && results.length === products.length && searchTerm !== '') {
