<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Singleton Theme Toggle</title>
    <style>
        /* Default light theme */
        body.light {
            background-color: white;
            color: black;
        }

        /* Dark theme */
        body.dark {
            background-color: black;
