    <script>
        // JavaScript for real-time email validation
        document.getElementById('emailInput').addEventListener('input', function() {
            const email = this.value;  // Get the current value of the input
            const regex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;  // Basic regex for email validation

            if (regex.test(email)) {
                // If valid, add 'valid' class and remove 'invalid'
                this.classList.add('valid');
                this.classList.remove('invalid');
            } else {
                // If invalid, add 'invalid' class and remove 'valid'
                this.classList.add('invalid');
                this.classList.remove('valid');
            }
        });
