    <script>
        // Function to generate Fibonacci sequence up to n terms
        function generateFibonacci(n) {
            const fib = [1, 1];  // Start with the first two Fibonacci numbers
            while (fib.length < n) {
                fib.push(fib[fib.length - 1] + fib[fib.length - 2]);
            }
            return fib;
        }

        // Function to draw the Fibonacci spiral on a given canvas context
        function drawFibonacciSpiral(ctx, isBuggy) {
            const canvasWidth = ctx.canvas.width;
            const canvasHeight = ctx.canvas.height;
            const centerX = canvasWidth / 2;
            const centerY = canvasHeight / 2;
            const scale = 20;  // Scaling factor for visibility
            const fib = generateFibonacci(8);  // Generate up to 8 Fibonacci numbers for the spiral
            let x = centerX;
            let y = centerY;
            let direction = 0;  // 0: right, 1: down, 2: left, 3: up
            const animationDuration = 2000;  // 2 seconds for the full animation
            const startTime = performance.now();
            const totalSteps = fib.length * 4;  // Arbitrary steps for smooth animation

            function animate(timestamp) {
                const elapsed = timestamp - startTime;
                const progress = Math.min(elapsed / animationDuration, 1);  // 0 to 1
                ctx.clearRect(0, 0, canvasWidth, canvasHeight);  // Clear canvas

                for (let i = 0; i < fib.length; i++) {
                    if (i > progress * fib.length) break;  // Only draw up to the current progress

                    const radius = isBuggy ? (fib[i + 1] || fib[i]) * scale : fib[i] * scale;  // Bug: Use fib[i+1] if possible
                    let arcX = x;
                    let arcY = y;
                    let startAngle, endAngle;

                    // Adjust center based on direction
                    if (direction === 0) {  // Right
                        arcX += radius;
                        arcY += radius;
                        startAngle = 0;
                        endAngle = -Math.PI / 2;  // Clockwise quarter-circle
                    } else if (direction === 1) {  // Down
                        arcX += radius;
                        arcY += radius;
                        startAngle = -Math.PI / 2;
                        endAngle = -Math.PI;
                    } else if (direction === 2) {  // Left
                        arcX -= radius;
                        arcY += radius;
                        startAngle = -Math.PI;
                        endAngle = -1.5 * Math.PI;
                    } else {  // Up
                        arcX -= radius;
                        arcY -= radius;
                        startAngle = -1.5 * Math.PI;
                        endAngle = -2 * Math.PI;  // Equivalent to 0
                    }

                    ctx.beginPath();
                    ctx.arc(arcX, arcY, radius, startAngle, endAngle, true);  // true for clockwise
                    ctx.strokeStyle = 'blue';
                    ctx.lineWidth = 2;
                    ctx.stroke();

                    // Update position for next arc (simulating the spiral growth)
                    if (direction === 0) x += radius * 2;  // Move right
                    else if (direction === 1) y += radius * 2;  // Move down
                    else if (direction === 2) x -= radius * 2;  // Move left
                    else y -= radius * 2;  // Move up

                    direction = (direction + 1) % 4;  // Change direction
                }

                if (progress < 1) {
                    requestAnimationFrame(animate);  // Continue animation
                }
            }

            requestAnimationFrame(animate);
        }

        // Initialize the canvases
        const buggyCtx = document.getElementById('buggyCanvas').getContext('2d');
        const fixedCtx = document.getElementById('fixedCanvas').getContext('2d');

        drawFibonacciSpiral(buggyCtx, true);  // Buggy version
        drawFibonacciSpiral(fixedCtx, false);  // Fixed version
