        function drawBuggySpiral(ctx, fib) {
            const centerX = ctx.canvas.width / 2;
            const centerY = ctx.canvas.height / 2;
            const startAngle = 0;  // Start angle in radians (0 = right)
            let currentAngle = startAngle;

            ctx.strokeStyle = 'blue';  // Blue for buggy spiral
            ctx.lineWidth = 2;

            fib.forEach(radius => {
                const actualRadius = radius * scaleFactor;
                ctx.beginPath();
                ctx.arc(centerX, centerY, actualRadius, currentAngle, currentAngle + (Math.PI / 2));  // Draw 90-degree arc
                ctx.stroke();
                currentAngle += Math.PI / 2;  // Increment angle for next arc
            });

            // The bug here: All arcs are drawn from the same center (centerX, centerY).
            // This results in concentric circles, not a spiral, because the centers aren't offset.
        }

