        function drawFixedSpiral(ctx, fib) {
            let currentX = ctx.canvas.width / 2;  // Start at the center
            let currentY = ctx.canvas.height / 2;
            let currentAngle = 0;  // Start angle in radians (0 = right)

            ctx.strokeStyle = 'green';  // Green for fixed spiral
            ctx.lineWidth = 2;

            fib.forEach(radius => {
                const actualRadius = radius * scaleFactor;

                // Draw the arc from the current center
                ctx.beginPath();
                ctx.arc(currentX, currentY, actualRadius, currentAngle, currentAngle + (Math.PI / 2));  // 90-degree arc
                ctx.stroke();

                // Calculate the endpoint of the current arc (where the next center should be)
                const endAngle = currentAngle + (Math.PI / 2);  // End angle of the current arc
                const endX = currentX + actualRadius * Math.cos(endAngle);  // X-coordinate of the endpoint
                const endY = currentY + actualRadius * Math.sin(endAngle);  // Y-coordinate of the endpoint

                // For the fixed version, update the center to the endpoint of the previous arc
                currentX = endX;  // New center X
                currentY = endY;  // New center Y
                currentAngle += Math.PI / 2;  // Increment angle for the next arc (turn 90 degrees)
            });

            // The fix: Each arc's center is updated to the endpoint of the previous arc,
            // creating a spiral by offsetting based on the Fibonacci radii.
        }

