                fixedList.appendChild(li);
                totalInCents += item.priceInCents;  // Add using integers
            });
            const totalInDollars = totalInCents / 100;  // Convert back to dollars
            fixedTotalSpan.textContent = totalInDollars.toFixed(2);

            // Demonstrate equality check (e.g., is total exactly 3.99?)
            if (totalInDollars === 3.99) {  // Using triple-equals after precise calculation
                fixedEqualityResult.textContent = 'Yes (precise calculation works)';
                fixedEqualityResult.className = 'success';
            } else {
                fixedEqualityResult.textContent = 'No';
                fixedEqualityResult.className = 'error';
            }
